import { ipcMain, shell } from 'electron';
import { IPC_CHANNELS, OpenExternalURLSchema, ApiResult } from './types';

export function registerBrowserHandlers() {
  // Open URL in external browser
  ipcMain.handle(IPC_CHANNELS.BROWSER_OPEN_EXTERNAL, async (_, input): Promise<ApiResult<void>> => {
    try {
      const { url } = OpenExternalURLSchema.parse(input);
      await shell.openExternal(url);
      return { success: true };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to open external URL',
      };
    }
  });
}
